update T_WMS_SEMIWORK
	set intf_yn = 'Y',
	intf_ymdhms = TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS'),
	ifno = #{ifno_if},
	mes_key = #{mes_key}
where itemcode = #{itemcode}
	and sdate = #{sdate}
	and barcode in(
		SELECT b.barcode
         FROM t_scm_barcode b
        WHERE b.lineno = #{line}
	)

