    (SELECT DISTINCT mes_key 
     FROM t_wms_semiwork
     WHERE sdate = #{sdate}
       AND barcode = #{barcode}
       AND mes_key IS NOT NULL
       AND ROWNUM = 1), 
    'none'
) AS mes_key
FROM dual

