UPDATE T_ST_CHANGESUB
SET qty=0, gqty=0, bqty=0, rgqty=0, rbqty=0
WHERE condate  = #{dateTo}
  AND roomcode = #{roomcode}

UPDATE T_ST_CHANGESUB t
SET t.gQty = TRUNC(NVL(t.rgQty, 0) - NVL(t.gSTOCK, 0), 2),
    t.bQty = TRUNC(NVL(t.rbQty, 0) - NVL(t.bStock, 0), 2)
WHERE t.condate  = #{dateTo}
  AND t.roomcode = #{roomcode}

UPDATE T_ST_CHANGESUB t
SET t.QTY = t.GQTY + t.BQTY
WHERE t.condate  = #{dateTo}
  AND t.roomcode = #{roomcode}

UPDATE T_ST_CHANGESUB t
SET t.STOCK = t.GSTOCK + t.BSTOCK
WHERE t.condate  = #{dateTo}
  AND t.roomcode = #{roomcode}

UPDATE T_MM_CHANGESUB
SET WGQTY=0, WBQTY=0, GQTY=0, BQTY=0, QTY=0
WHERE condate = #{dateTo}
  AND WCcode  = #{wccode}

UPDATE T_MM_CHANGESUB t
SET t.gQty = TRUNC(NVL(t.wgQty, 0) - NVL(t.gSTOCK, 0), 2),
    t.bQty = TRUNC(NVL(t.wbQty, 0) - NVL(t.bStock, 0), 2)
WHERE t.condate = #{dateTo}
  AND t.WCcode  = #{wccode}

UPDATE T_MM_CHANGESUB t
SET t.QTY = t.GQTY + t.BQTY
WHERE t.condate = #{dateTo}
  AND t.WCcode  = #{wccode}

UPDATE T_MM_CHANGESUB t
SET t.STOCK = t.GSTOCK + t.BSTOCK
WHERE t.condate = #{dateTo}
  AND t.WCcode  = #{wccode}
